css:
.loader {color: var(--loader-color, #e11d48);
  --loader-secondary-color: #fb7185;
  --loader-bg: #ffffff;
  width: 20px;
  aspect-ratio: 1;
  border-radius: 50%;
  background: currentColor;
  box-shadow: 0 0 0 0 color-mix(in srgb, currentColor 25%, transparent);
  animation: l1 1s infinite;
}@keyframes l1 {100% {box-shadow: 0 0 0 30px #0000}}
